  globals.window["GENESIS_DELTA"] = null
  globals.window["GENESIS_START_TIME"] = null
  globals.window["GENESIS_FRAME"] = null
  globals.window["GENESIS_SOUND_DELAY_FRAME"] = 8
  globals.window["GENESIS_AUDIO_CONTENT"] = null
  globals.window["GENESIS_AUDIO_L"] = null
  globals.window["GENESIS_AUDIO_R"] = null
  globals.window["GENESIS_SOUND_SHED_TIME"] = 0
  globals.window["GENESIS_SOUND_DELAYED_TIME"] = null

  function loadROM(ROM) {
    try {
      var bytes = ROM

      // Get the memory buffer - in Emscripten the heap arrays share the same underlying buffer
      var buffer = GENESIS.HEAPU8.buffer
      var romBufferPtr = GENESIS._get_rom_buffer_ref(bytes.byteLength)

      // Create view into the ROM buffer area
      globals.window["GENESIS_ROMDATA"] = new Uint8Array(
        buffer,
        romBufferPtr,
        bytes.byteLength
      )

      // Copy ROM data into the buffer
      globals.window["GENESIS_ROMDATA"].set(new Uint8Array(bytes))

      // Start emulation
      start()
    } catch (error) {
      //
    }
  }

  function start() {
    globals.window["GENESIS_CANVAS_CONTEXT"].clearRect(
      0,
      0,
      globals.window["GENESIS_CANVAS"].width,
      globals.window["GENESIS_CANVAS"].height
    )
    GENESIS._start()

    // Check if game is PAL or NTSC and adjust sample rate accordingly
    var isPal = GENESIS._is_pal()
    if (isPal) {
      // PAL: 49.70 Hz -> 44100 / 49.70 = ~887.5 samples per frame
      globals.window["GENESIS_SAMPLING_PER_FPS"] = 887
      globals.window["GENESIS_FPS"] = 50
    } else {
      // NTSC: 59.92 Hz -> 44100 / 59.92 = ~736 samples per frame
      globals.window["GENESIS_SAMPLING_PER_FPS"] = 736
      globals.window["GENESIS_FPS"] = 60
    }

    // For iOS dummy audio
    var audioBuffer = globals.window["GENESIS_AUDIO_CONTENT"].createBuffer(
      2,
      globals.window["GENESIS_SAMPLING_PER_FPS"],
      globals.window["GENESIS_SOUND_FREQUENCY"]
    )
    var dummy = new Float32Array(globals.window["GENESIS_SAMPLING_PER_FPS"])
    dummy.fill(0)
    audioBuffer.getChannelData(0).set(dummy)
    audioBuffer.getChannelData(1).set(dummy)
    sound(audioBuffer)

    globals.window["GENESIS_INTERVAL"] = 1000 / globals.window["GENESIS_FPS"]

    // Update sound delay time based on actual sample rate
    globals.window["GENESIS_SOUND_DELAYED_TIME"] =
      (globals.window["GENESIS_SAMPLING_PER_FPS"] *
        globals.window["GENESIS_SOUND_DELAY_FRAME"]) /
      globals.window["GENESIS_SOUND_FREQUENCY"]

    globals.window["GENESIS_VRAM"] = new Uint8ClampedArray(
      GENESIS.HEAPU8.buffer,
      GENESIS._get_frame_buffer_ref(),
      globals.window["GENESIS_CANVAS_WIDTH"] *
        globals.window["GENESIS_CANVAS_HEIGHT"] *
        4
    )
    globals.window["GENESIS_AUDIO_L"] = new Float32Array(
      GENESIS.HEAPF32.buffer,
      GENESIS._get_web_audio_l_ref(),
      globals.window["GENESIS_SAMPLING_PER_FPS"]
    )
    globals.window["GENESIS_AUDIO_R"] = new Float32Array(
      GENESIS.HEAPF32.buffer,
      GENESIS._get_web_audio_r_ref(),
      globals.window["GENESIS_SAMPLING_PER_FPS"]
    )
    globals.window["GENESIS_INPUT"] = new Float32Array(
      GENESIS.HEAPF32.buffer,
      GENESIS._get_input_buffer_ref(),
      globals.window["GENESIS_GAMEPAD_API_INDEX"]
    )
    globals.window["GENESIS_THEN"] = Date.now()
    if (globals.window["GENESIS_RUNNING_CALLBACK"]) {
      globals.window["GENESIS_RUNNING_CALLBACK"]()
    }
    loop()
  }

  function keyscan() {
    if (!globals.window["GENESIS_INPUT"]) {
      return
    }

    globals.window["GENESIS_INPUT"].fill(0)

    // Player 1 input
    if (keys1["up"]) {
      globals.window["GENESIS_INPUT"][7] = -1
    } else if (keys1["down"]) {
      globals.window["GENESIS_INPUT"][7] = 1
    }

    if (keys1["left"]) {
      globals.window["GENESIS_INPUT"][6] = -1
    } else if (keys1["right"]) {
      globals.window["GENESIS_INPUT"][6] = 1
    }

    // Button mappings
    if (keys1["a"]) {
      // INPUT_A
      globals.window["GENESIS_INPUT"][8 + 2] = 1
    }
    if (keys1["b"]) {
      // INPUT_B
      globals.window["GENESIS_INPUT"][8 + 3] = 1
    }
    if (keys1["c"]) {
      // INPUT_C
      globals.window["GENESIS_INPUT"][8 + 1] = 1
    }
    if (keys1["start"]) {
      // INPUT_START
      globals.window["GENESIS_INPUT"][8 + 7] = 1
    }
    if (keys1["x"]) {
      // INPUT_X
      globals.window["GENESIS_INPUT"][8 + 0] = 1
    }
    if (keys1["y"]) {
      // INPUT_Y
      globals.window["GENESIS_INPUT"][8 + 4] = 1
    }
    if (keys1["z"]) {
      // INPUT_Z
      globals.window["GENESIS_INPUT"][8 + 5] = 1
    }
    if (keys1["mode"]) {
      // INPUT_MODE
      globals.window["GENESIS_INPUT"][8 + 6] = 1
    }

    // Player 2 input
    if (keys2["up"]) {
      globals.window["GENESIS_INPUT"][16 + 7] = -1
    } else if (keys2["down"]) {
      globals.window["GENESIS_INPUT"][16 + 7] = 1
    }

    if (keys2["left"]) {
      globals.window["GENESIS_INPUT"][16 + 6] = -1
    } else if (keys2["right"]) {
      globals.window["GENESIS_INPUT"][16 + 6] = 1
    }

    // Player 2 button mappings
    if (keys2["a"]) {
      // INPUT_A
      globals.window["GENESIS_INPUT"][16 + 8 + 2] = 1
    }
    if (keys2["b"]) {
      // INPUT_B
      globals.window["GENESIS_INPUT"][16 + 8 + 3] = 1
    }
    if (keys2["c"]) {
      // INPUT_C
      globals.window["GENESIS_INPUT"][16 + 8 + 1] = 1
    }
    if (keys2["start"]) {
      // INPUT_START
      globals.window["GENESIS_INPUT"][16 + 8 + 7] = 1
    }
    if (keys2["x"]) {
      // INPUT_X
      globals.window["GENESIS_INPUT"][16 + 8 + 0] = 1
    }
    if (keys2["y"]) {
      // INPUT_Y
      globals.window["GENESIS_INPUT"][16 + 8 + 4] = 1
    }
    if (keys2["z"]) {
      // INPUT_Z
      globals.window["GENESIS_INPUT"][16 + 8 + 5] = 1
    }
    if (keys2["mode"]) {
      // INPUT_MODE
      globals.window["GENESIS_INPUT"][16 + 8 + 6] = 1
    }
  }

  function sound(audioBuffer) {
    var source = globals.window["GENESIS_AUDIO_CONTENT"].createBufferSource()
    source.buffer = audioBuffer
    source.connect(globals.window["GENESIS_AUDIO_CONTENT"].destination)
    var currentSoundTime = globals.window["GENESIS_AUDIO_CONTENT"].currentTime
    if (currentSoundTime < globals.window["GENESIS_SOUND_SHED_TIME"]) {
      source.start(globals.window["GENESIS_SOUND_SHED_TIME"])
      globals.window["GENESIS_SOUND_SHED_TIME"] += audioBuffer.duration
    } else {
      source.start(currentSoundTime)
      globals.window["GENESIS_SOUND_SHED_TIME"] =
        currentSoundTime +
        audioBuffer.duration +
        globals.window["GENESIS_SOUND_DELAYED_TIME"]
    }
  }

  function loop() {
    requestAnimationFrame(loop)
    globals.window["GENESIS_NOW"] = Date.now()
    globals.window["GENESIS_DELTA"] =
      globals.window["GENESIS_NOW"] - globals.window["GENESIS_THEN"]
    if (
      globals.window["GENESIS_DELTA"] > globals.window["GENESIS_INTERVAL"] &&
      !globals.window["GENESIS_GAME_PAUSED"]
    ) {
      keyscan()
      // Update
      GENESIS._tick()
      globals.window["GENESIS_THEN"] =
        globals.window["GENESIS_NOW"] -
        (globals.window["GENESIS_DELTA"] % globals.window["GENESIS_INTERVAL"])
      // Draw
      globals.window["GENESIS_CANVAS_IMAGE_DATA"].data.set(
        globals.window["GENESIS_VRAM"]
      )
      globals.window["GENESIS_CANVAS_CONTEXT"].putImageData(
        globals.window["GENESIS_CANVAS_IMAGE_DATA"],
        0,
        0
      )
      // FPS
      globals.window["GENESIS_FRAME"]++
      if (new Date().getTime() - globals.window["GENESIS_START_TIME"] >= 1000) {
        globals.window["GENESIS_CURRENT_FPS"] = globals.window["GENESIS_FRAME"]
        globals.window["GENESIS_FRAME"] = 0
        globals.window["GENESIS_START_TIME"] = new Date().getTime()
      }
      // Sound
      GENESIS._sound()
      // Sound hack
      if (globals.window["GENESIS_CURRENT_FPS"] < globals.window["GENESIS_FPS"]) {
        globals.window["GENESIS_SOUND_SHED_TIME"] = 0
      } else {
        if (globals.window["GENESIS_SOUND_ENABLED"] === false) {
          silentSoundFrame()
        } else {
          var audioBuffer = globals.window["GENESIS_AUDIO_CONTENT"].createBuffer(
            2,
            globals.window["GENESIS_SAMPLING_PER_FPS"],
            globals.window["GENESIS_SOUND_FREQUENCY"]
          )
          audioBuffer.getChannelData(0).set(globals.window["GENESIS_AUDIO_L"])
          audioBuffer.getChannelData(1).set(globals.window["GENESIS_AUDIO_R"])
          sound(audioBuffer)
        }
      }
    }
  }

  // Keyboard state
  var keys1 = {}
  var keys2 = {}

  // Default keyboard mapping for Genesis controls
  var defaultKeyMap = {
    [1]: {
      ArrowUp: "up",
      ArrowDown: "down",
      ArrowLeft: "left",
      ArrowRight: "right",
      KeyZ: "a", // A button
      KeyX: "b", // B button
      KeyC: "c", // C button
      KeyA: "x", // X button
      KeyS: "y", // Y button
      KeyD: "z", // Z button
      Enter: "start", // Start button
    },
    [2]: {
      KeyI: "up",
      KeyK: "down",
      KeyJ: "left",
      KeyL: "right",
      KeyB: "a", // A button
      KeyN: "b", // B button
      KeyM: "c", // C button
      KeyU: "x", // X button
      KeyO: "y", // Y button
      KeyP: "z", // Z button
      KeyH: "start", // Start button
    },
  }

  // Build keyMap from player configuration
  function buildKeyMap(playerConfig, playerNumber) {
    var keyMap = {}

    if (playerConfig) {
      // Map each Genesis control to its configured key
      var controls = [
        "up",
        "down",
        "left",
        "right",
        "a",
        "b",
        "c",
        "x",
        "y",
        "z",
        "start",
      ]

      for (var i = 0; i < controls.length; i++) {
        var control = controls[i]
        if (playerConfig[control]) {
          var keyCode = playerConfig[control]
          if (keyCode) {
            keyMap[keyCode] = control
          }
        }
      }

      // Add mode button defaults if not configured
      if (!keyMap["ShiftRight"]) keyMap["ShiftRight"] = "mode"
      if (!keyMap["ShiftLeft"]) keyMap["ShiftLeft"] = "mode"
    } else {
      // Use default mapping if no player config provided
      keyMap = defaultKeyMap[playerNumber]
    }

    return keyMap
  }

  function embedGenesis(config) {
    // Validate config object (required)
    if (typeof config !== "object") {
      throw new Error("Error. A configuration is required.")
    }

    // Validate container (required)
    if (!config.container || typeof config.container !== "string") {
      throw new Error(
        "Error. 'container' is required and must be a string (element ID)."
      )
    }
    if (!document.getElementById(config.container)) {
      throw new Error(
        "Error. 'container' element with ID '" +
          config.container +
          "' does not exist."
      )
    }

    // Validate name (required)
    if (typeof config.name !== "string") {
      throw new Error("Error. 'name' is required.")
    }

    // Validate rom (required)
    if (!(config.rom instanceof ArrayBuffer)) {
      throw new Error("Error. 'rom' must be an ArrayBuffer.")
    }

    // Validate player1 (optional)
    if (config.player1 !== undefined) {
      if (typeof config.player1 !== "object" || config.player1 === null) {
        throw new Error("Error. 'player1' must be an object.")
      }
      var validKeys = [
        "up",
        "down",
        "left",
        "right",
        "a",
        "b",
        "c",
        "x",
        "y",
        "z",
        "select",
        "start",
      ]
      for (var key in config.player1) {
        if (validKeys.indexOf(key) === -1) {
          throw new Error(
            "Error. Invalid key '" + key + "' in player1 configuration."
          )
        }
        if (typeof config.player1[key] !== "string") {
          throw new Error("Error. 'player1." + key + "' must be a string.")
        }
      }
    }

    // Validate player2 (optional)
    if (config.player2 !== undefined) {
      if (typeof config.player2 !== "object" || config.player2 === null) {
        throw new Error("Error. 'player2' must be an object.")
      }
      var validKeys = [
        "up",
        "down",
        "left",
        "right",
        "a",
        "b",
        "c",
        "x",
        "y",
        "z",
        "select",
        "start",
      ]
      for (var key in config.player2) {
        if (validKeys.indexOf(key) === -1) {
          throw new Error(
            "Error. Invalid key '" + key + "' in player2 configuration."
          )
        }
        if (typeof config.player2[key] !== "string") {
          throw new Error("Error. 'player2." + key + "' must be a string.")
        }
      }
    }

    // Validate cbStarted (optional)
    if (config.cbStarted !== undefined && typeof config.cbStarted !== "function") {
      throw new Error("Error. 'cbStarted' must be a function.")
    }

    // Build keyMap from player1 configuration or use defaults
    var keyMap1 = buildKeyMap(config.player1, 1)
    // Build keyMap for player2 if configured
    var keyMap2 = buildKeyMap(config.player2, 2)

    // Canvas setting
    globals.window["GENESIS_CANVAS"] = document.createElement("canvas")
    globals.window["GENESIS_CANVAS"].setAttribute(
      "width",
      globals.window["GENESIS_CANVAS_WIDTH"]
    )
    globals.window["GENESIS_CANVAS"].setAttribute(
      "height",
      globals.window["GENESIS_CANVAS_HEIGHT"]
    )
    globals.window["GENESIS_CANVAS_CONTEXT"] =
      globals.window["GENESIS_CANVAS"].getContext("2d")
    globals.window["GENESIS_CANVAS_IMAGE_DATA"] = globals.window[
      "GENESIS_CANVAS_CONTEXT"
    ].createImageData(
      globals.window["GENESIS_CANVAS_WIDTH"],
      globals.window["GENESIS_CANVAS_HEIGHT"]
    )
    document
      .getElementById(config.container)
      .appendChild(globals.window["GENESIS_CANVAS"])

    document.getElementById(config.container).style.overflowY = "hidden"

    globals.window["GENESIS_CONTAINER"] = config.container

    // get the filename from the full url
    var filename = config.name
    if (/^https?:\/\//i.test(filename)) {
      var parts = filename.split("/")
      var lastPart = parts[parts.length - 1]
      filename = lastPart ? lastPart : null

      if (!filename) {
        throw Error(
          "Error. The URL must contain the filename, like https://www.example.com/myFile.bin"
        )
      }
    }

    filename = filename.split(".").slice(0, -1).join(".")

    globals.window["GENESIS_GAME_NAME"] = filename
    globals.window["GENESIS_RUNNING_CALLBACK"] = config.cbStarted

    function resizeChildren() {
      var parent = document.getElementById(config.container)
      if (!parent) {
        return
      }

      // get visual box
      var rect = parent.getBoundingClientRect()
      var style = window.getComputedStyle(parent)

      // take into account margins
      var marginTop = parseFloat(style.marginTop) || 0
      var marginLeft = parseFloat(style.marginLeft) || 0

      var width = rect.width
      var height = rect.height

      // ensure parent can position children correctly
      parent.style.position = "relative"

      var overlay = document.getElementById(globals.window["GENESIS_CONTAINER"])

      // --- Safari pointer-lock workaround ---
      var isSafari = /^((?!chrome|android).)*safari/i.test(navigator.userAgent)
      var pointerLocked = document.pointerLockElement === overlay
      var restoreMargin = false

      if (isSafari && pointerLocked) {
        // temporarily remove margins so Safari computes layout correctly
        parent.setAttribute("data-saved-margin-top", parent.style.marginTop)
        parent.setAttribute("data-saved-margin-left", parent.style.marginLeft)
        parent.style.marginTop = "0px"
        parent.style.marginLeft = "0px"
        restoreMargin = true
        marginTop = 0
        marginLeft = 0
      }

      // --- Canvas ---
      globals.window["GENESIS_CANVAS"].style.position = "absolute"
      globals.window["GENESIS_CANVAS"].style.left = marginLeft + "px"
      globals.window["GENESIS_CANVAS"].style.top = marginTop + "px"
      globals.window["GENESIS_CANVAS"].style.width = width + "px"
      globals.window["GENESIS_CANVAS"].style.height =
        Math.floor(height + height * 0.072) + "px"
      globals.window["GENESIS_CANVAS"].style.zIndex = "9997"

      // --- Restore margins after resize (Safari only) ---
      if (restoreMargin) {
        parent.style.marginTop = parent.getAttribute("data-saved-margin-top") || ""
        parent.style.marginLeft = parent.getAttribute("data-saved-margin-left") || ""
        parent.removeAttribute("data-saved-margin-top")
        parent.removeAttribute("data-saved-margin-left")
      }
    }

    // initial resize
    resizeChildren()

    var resizeTimeout

    function onResizeEvent() {
      // waiting 25 ms for the browser UI to be updated
      clearTimeout(resizeTimeout)
      resizeTimeout = setTimeout(function () {
        resizeChildren()
      }, 25)
    }

    if (window.addEventListener) {
      window.addEventListener("resize", onResizeEvent, false)
    } else if (window.attachEvent) {
      window.attachEvent("onresize", onResizeEvent)
    }

    document.addEventListener("mousemove", function (event) {
      try {
        document.getElementById(globals.window["GENESIS_CONTAINER"]).style.cursor =
          "default"
      } catch (err) {
        //
      }
    })

    document.addEventListener("keydown", function (e) {
      setTimeout(function () {
        document.getElementById(globals.window["GENESIS_CONTAINER"]).style.cursor =
          "none"
      }, 0)

      var KEY_CTRL = e.ctrlKey || e.metaKey
      if (KEY_CTRL) {
        return
      }

      var action = keyMap1[e.code]
      if (action) {
        keys1[action] = true
        e.preventDefault()
      }
      var action2 = keyMap2[e.code]
      if (action2) {
        keys2[action2] = true
        e.preventDefault()
      }
    })

    document.addEventListener("keyup", function (e) {
      var KEY_CTRL = e.ctrlKey || e.metaKey
      if (KEY_CTRL) {
        return
      }

      var action = keyMap1[e.code]
      if (action) {
        keys1[action] = false
        e.preventDefault()
      }
      var action2 = keyMap2[e.code]
      if (action2) {
        keys2[action2] = false
        e.preventDefault()
      }
    })

    function silentSoundFrame() {
      try {
        var audioBuffer = globals.window["GENESIS_AUDIO_CONTENT"].createBuffer(
          2,
          globals.window["GENESIS_SAMPLING_PER_FPS"],
          globals.window["GENESIS_SOUND_FREQUENCY"]
        )
        audioBuffer
          .getChannelData(0)
          .set(new Float32Array(globals.window["GENESIS_SAMPLING_PER_FPS"]))
        audioBuffer
          .getChannelData(1)
          .set(new Float32Array(globals.window["GENESIS_SAMPLING_PER_FPS"]))
        sound(audioBuffer)
      } catch (err) {
        //
      }
    }

    globals.window["silentSoundFrame"] = silentSoundFrame

    window.addEventListener("focus", function () {
      globals.window["GENESIS_GAME_PAUSED"] = false
      globals.window["silentSoundFrame"]()
    })

    window.addEventListener("blur", function () {
      globals.window["GENESIS_GAME_PAUSED"] = true
      globals.window["silentSoundFrame"]()
    })

    globals.window["GENESIS_CURRENT_FPS"] = 0
    globals.window["GENESIS_FRAME"] = globals.window["GENESIS_FPS"]
    globals.window["GENESIS_START_TIME"] = new Date().getTime()

    // Audio init
    globals.window["GENESIS_AUDIO_CONTENT"] = new (window.AudioContext ||
      window.webkitAudioContext)({
      sampleRate: globals.window["GENESIS_SOUND_FREQUENCY"],
    })

    // Initialize emulator
    Module()
      .then(function (module) {
        GENESIS = module

        // Wait for runtime to be initialized
        if (GENESIS.calledRun) {
          finishInit()
        } else {
          GENESIS.onRuntimeInitialized = finishInit
        }

        function finishInit() {
          // Memory allocate
          GENESIS._init()

          // Loading ROM
          loadROM(config.rom)
        }
      })
      .catch(function (_err) {
        //
      })
  }

  globals.window["embedGenesis"] = embedGenesis

  function downloadStateGenesis() {
    try {
      // Call the C function to save state to the buffer
      var stateSize = GENESIS._save_state()

      if (stateSize === 0) {
        return
      }

      // Get the state buffer reference
      var stateBufferPtr = GENESIS._get_state_buffer_ref()
      var actualSize = GENESIS._get_state_size()

      // Copy the state data from WASM memory
      var stateData = new Uint8Array(
        GENESIS.HEAPU8.buffer,
        stateBufferPtr,
        actualSize
      )
      var stateCopy = new Uint8Array(stateData)

      // Create a blob and download it
      var blob = new Blob([stateCopy], { type: "application/octet-stream" })
      var url = URL.createObjectURL(blob)
      var link = document.createElement("a")
      link.href = url
      link.download = globals.window["GENESIS_GAME_NAME"] + ".state"
      document.body.appendChild(link)
      link.click()
      document.body.removeChild(link)
      URL.revokeObjectURL(url)
    } catch (error) {
      //
    }
  }

  globals.window["downloadStateGenesis"] = downloadStateGenesis

  function uploadStateGenesis() {
    try {
      // Create a file input element
      var input = document.createElement("input")
      input.type = "file"
      input.accept = ".state"

      input.onchange = function (event) {
        var file = event.target.files[0]
        if (!file) {
          return
        }

        var reader = new FileReader()
        reader.onload = function (e) {
          try {
            var originalSoundState = globals.window["GENESIS_SOUND_ENABLED"]
            globals.window["GENESIS_SOUND_ENABLED"] = false
            var arrayBuffer = e.target.result
            var stateData = new Uint8Array(arrayBuffer)

            // Get the state buffer reference
            var stateBufferPtr = GENESIS._get_state_buffer_ref()
            var stateSize = GENESIS._get_state_size()

            // Verify the size
            if (stateData.length > stateSize) {
              console.log("State file too large")
              return
            }

            // Copy the state data into WASM memory
            var stateBuffer = new Uint8Array(
              GENESIS.HEAPU8.buffer,
              stateBufferPtr,
              stateSize
            )
            stateBuffer.set(stateData)

            // Call the C function to load state from the buffer
            GENESIS._load_state()
            globals.window["GENESIS_SOUND_ENABLED"] = originalSoundState
          } catch (error) {
            //
          }
        }

        reader.readAsArrayBuffer(file)
      }

      input.click()
    } catch (error) {
      //
    }
  }

  globals.window["uploadStateGenesis"] = uploadStateGenesis

